  const nonBiddingTeamColorClass = biddingTeam === "us" ? "bg-accent" : "bg-primary";

  const focusRingColor = biddingTeam === "us" ? "focus:ring-blue-500 dark:focus:ring-blue-400" : "focus:ring-red-500 dark:focus:ring-red-400";

